import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 8 — Opening, Saving and Quitting","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/08-opening-saving-quitting.md","filePath":"chapters/08-opening-saving-quitting.md"}'),n={name:"chapters/08-opening-saving-quitting.md"};function o(d,e,l,p,c,r){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="chapter-8-—-opening-saving-and-quitting" tabindex="-1">Chapter 8 — Opening, Saving and Quitting <a class="header-anchor" href="#chapter-8-—-opening-saving-and-quitting" aria-label="Permalink to &quot;Chapter 8 — Opening, Saving and Quitting&quot;">​</a></h1><blockquote><p><em>&quot;Every Vim session starts with opening a file and ends with saving your work.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐ Beginner <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>File operations are the most basic tasks in any editor.</p><p>In Vim, they&#39;re done through <strong>commands</strong> (starting with <code>:</code>) or <strong>key sequences</strong>.</p><p>By the end of this chapter, you&#39;ll be able to:</p><ul><li>Open files in multiple ways</li><li>Save files with different options</li><li>Quit Vim gracefully</li><li>Handle multiple files</li></ul><hr><h1 id="opening-files" tabindex="-1">Opening Files <a class="header-anchor" href="#opening-files" aria-label="Permalink to &quot;Opening Files&quot;">​</a></h1><h2 id="from-the-terminal" tabindex="-1">From the Terminal <a class="header-anchor" href="#from-the-terminal" aria-label="Permalink to &quot;From the Terminal&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> filename.txt</span></span></code></pre></div><p>Opens <code>filename.txt</code> in Vim.</p><p>If the file doesn&#39;t exist, Vim creates a new buffer.</p><h2 id="open-multiple-files" tabindex="-1">Open Multiple Files <a class="header-anchor" href="#open-multiple-files" aria-label="Permalink to &quot;Open Multiple Files&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file1.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file2.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file3.txt</span></span></code></pre></div><p>Vim opens the first file. Use these commands to switch:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:next</code> or <code>:n</code></td><td>Go to next file</td></tr><tr><td><code>:previous</code> or <code>:N</code> or <code>:prev</code></td><td>Go to previous file</td></tr><tr><td><code>:first</code></td><td>Go to first file</td></tr><tr><td><code>:last</code></td><td>Go to last file</td></tr><tr><td><code>:args</code></td><td>Show list of open files</td></tr></tbody></table><h2 id="open-a-file-from-inside-vim" tabindex="-1">Open a File From Inside Vim <a class="header-anchor" href="#open-a-file-from-inside-vim" aria-label="Permalink to &quot;Open a File From Inside Vim&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:e filename.txt</span></span></code></pre></div><p>Short for <strong>edit</strong>. Opens <code>filename.txt</code> in the current buffer.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:e /path/to/file</span></span></code></pre></div><p>Opens a file from an absolute path.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:e *.txt</span></span></code></pre></div><p>Opens a wildcard match (with tab completion).</p><h2 id="using-tab-completion" tabindex="-1">Using Tab Completion <a class="header-anchor" href="#using-tab-completion" aria-label="Permalink to &quot;Using Tab Completion&quot;">​</a></h2><p>Type a partial path and press <strong>Tab</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:e /etc/ng[TAB]</span></span>
<span class="line"><span>:e /etc/nginx/</span></span></code></pre></div><p>Vim completes the path.</p><hr><h1 id="saving-files" tabindex="-1">Saving Files <a class="header-anchor" href="#saving-files" aria-label="Permalink to &quot;Saving Files&quot;">​</a></h1><h2 id="basic-save" tabindex="-1">Basic Save <a class="header-anchor" href="#basic-save" aria-label="Permalink to &quot;Basic Save&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:w</span></span></code></pre></div><p>Writes the current buffer to disk.</p><h2 id="save-as" tabindex="-1">Save As <a class="header-anchor" href="#save-as" aria-label="Permalink to &quot;Save As&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:w newname.txt</span></span></code></pre></div><p>Saves with a new name. The original file remains unchanged.</p><h2 id="save-to-a-different-location" tabindex="-1">Save to a Different Location <a class="header-anchor" href="#save-to-a-different-location" aria-label="Permalink to &quot;Save to a Different Location&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:w /path/to/backup.txt</span></span></code></pre></div><p>Saves a copy to the specified path.</p><h2 id="save-and-quit" tabindex="-1">Save and Quit <a class="header-anchor" href="#save-and-quit" aria-label="Permalink to &quot;Save and Quit&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:wq</span></span></code></pre></div><p>Save changes and exit.</p><h2 id="save-with-sudo" tabindex="-1">Save with Sudo <a class="header-anchor" href="#save-with-sudo" aria-label="Permalink to &quot;Save with Sudo&quot;">​</a></h2><p>When you open a file without <code>sudo</code> but need to save:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:w !sudo tee %</span></span></code></pre></div><p>This runs the write command through <code>sudo</code>.</p><hr><h1 id="quitting-vim" tabindex="-1">Quitting Vim <a class="header-anchor" href="#quitting-vim" aria-label="Permalink to &quot;Quitting Vim&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:q</code></td><td>Quit (only if no unsaved changes)</td></tr><tr><td><code>:q!</code></td><td>Force quit, discard changes</td></tr><tr><td><code>:wq</code></td><td>Save and quit</td></tr><tr><td><code>:x</code></td><td>Save and quit (same as <code>:wq</code>)</td></tr><tr><td><code>ZZ</code></td><td>Save and quit (normal mode)</td></tr><tr><td><code>ZQ</code></td><td>Quit without saving (normal mode)</td></tr></tbody></table><h2 id="quit-all-files" tabindex="-1">Quit All Files <a class="header-anchor" href="#quit-all-files" aria-label="Permalink to &quot;Quit All Files&quot;">​</a></h2><p>If you have multiple files open:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:qa</span></span></code></pre></div><p>Quit all.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:qa!</span></span></code></pre></div><p>Force quit all, discarding changes.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:wqa</span></span></code></pre></div><p>Save all and quit.</p><hr><h1 id="discarding-changes" tabindex="-1">Discarding Changes <a class="header-anchor" href="#discarding-changes" aria-label="Permalink to &quot;Discarding Changes&quot;">​</a></h1><p>Sometimes you edit a file and want to <strong>discard all changes</strong>.</p><p>To reload the original file from disk:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:e!</span></span></code></pre></div><p>This discards all modifications since the last save.</p><h2 id="abandon-changes-and-quit" tabindex="-1">Abandon Changes and Quit <a class="header-anchor" href="#abandon-changes-and-quit" aria-label="Permalink to &quot;Abandon Changes and Quit&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:cq</span></span></code></pre></div><p>Quit with an error code (useful for Git when you want to abort a commit).</p><hr><h1 id="understanding-the-status-line" tabindex="-1">Understanding the Status Line <a class="header-anchor" href="#understanding-the-status-line" aria-label="Permalink to &quot;Understanding the Status Line&quot;">​</a></h1><p>When you save, Vim shows a message:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;filename.txt&quot; 10L, 234B written</span></span></code></pre></div><p>This means:</p><ul><li>10 lines</li><li>234 bytes</li><li>File saved</li></ul><p>If the file is new:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;filename.txt&quot; [New] 10L, 234B written</span></span></code></pre></div><p>If there are unsaved changes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;filename.txt&quot; 10L, 234B written</span></span></code></pre></div><p>Vim displays indicators like <code>[+]</code> or <code>[Modified]</code> in the status line.</p><hr><h1 id="reading-files-into-a-buffer" tabindex="-1">Reading Files Into a Buffer <a class="header-anchor" href="#reading-files-into-a-buffer" aria-label="Permalink to &quot;Reading Files Into a Buffer&quot;">​</a></h1><p>You can insert the content of another file into the current buffer:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:r otherfile.txt</span></span></code></pre></div><p>Reads <code>otherfile.txt</code> and inserts it below the cursor.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:0r otherfile.txt</span></span></code></pre></div><p>Reads and inserts at the beginning of the file.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:r !command</span></span></code></pre></div><p>Reads the output of a shell command:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:r !date</span></span></code></pre></div><p>Inserts the current date and time.</p><hr><h1 id="file-operations-cheat-sheet" tabindex="-1">File Operations Cheat Sheet <a class="header-anchor" href="#file-operations-cheat-sheet" aria-label="Permalink to &quot;File Operations Cheat Sheet&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Action</th><th>Command</th></tr></thead><tbody><tr><td>Open file</td><td><code>:e file</code></td></tr><tr><td>Save</td><td><code>:w</code></td></tr><tr><td>Save as</td><td><code>:w name</code></td></tr><tr><td>Save and quit</td><td><code>:wq</code></td></tr><tr><td>Quit</td><td><code>:q</code></td></tr><tr><td>Force quit</td><td><code>:q!</code></td></tr><tr><td>Save all</td><td><code>:wa</code></td></tr><tr><td>Quit all</td><td><code>:qa</code></td></tr><tr><td>Save and quit all</td><td><code>:wqa</code></td></tr><tr><td>Next file</td><td><code>:n</code></td></tr><tr><td>Previous file</td><td><code>:prev</code></td></tr><tr><td>Reload from disk</td><td><code>:e!</code></td></tr><tr><td>Insert file contents</td><td><code>:r file</code></td></tr><tr><td>Insert command output</td><td><code>:r !cmd</code></td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li>Open files with <code>vim filename</code> or <code>:e filename</code> inside Vim.</li><li>Save with <code>:w</code>, save as with <code>:w newname</code>.</li><li>Quit with <code>:q</code>, force quit with <code>:q!</code>.</li><li>Save and quit with <code>:wq</code> or <code>ZZ</code>.</li><li><code>ZZ</code> and <code>ZQ</code> are normal-mode shortcuts that skip the colon.</li><li>Use <code>:r</code> to insert file contents or command output into your buffer.</li></ul><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>File commands always start with <code>:</code>.</li><li>Press Enter to execute a command.</li><li><code>!</code> forces an action (quit without saving, overwrite, etc.).</li><li><code>:wq</code> saves and quits in one step.</li><li><code>:e!</code> reloads the file from disk, discarding changes.</li><li>Multiple files can be opened and managed from the command line.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Create a new file, write some text, save it, and quit.</li><li>Reopen the file, add a line, and save using <code>ZZ</code>.</li><li>Open three files at once and practice switching between them with <code>:n</code> and <code>:prev</code>.</li><li>Insert the output of <code>:r !ls</code> into a text file.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./09-cursor-movement.html"><strong>Chapter 9 — Cursor Movement</strong></a></p><p>Now that you can open and save files, let&#39;s learn how to move around efficiently.</p>`,107)])])}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
